div.script:
(function () {
    var btn  = document.getElementById('sc_insc_btn');
    var form = btn.closest('form');

    btn.addEventListener('click', function () {
        // Feedback visuel immédiat
        btn.textContent = 'Création en cours…';
        btn.style.opacity = '0.7';
        btn.disabled = true;

        // Soumission NATIVE — bypasse jQuery/Odoo qui intercepte submit()
        HTMLFormElement.prototype.submit.call(form);
    });
})();

i.t-attf-class:
fa #{
                                'fa-star text-warning' if i < provider.rating_avg
                                else 'fa-star-o text-white'}

span.t-attf-class:
badge rounded-pill #{
                                'text-bg-success' if m.state == 'done' else
                                'text-bg-primary' if m.state == 'in_progress' else
                                'text-bg-warning' if m.state == 'confirmed' else
                                'text-bg-danger' if m.state == 'cancelled' else
                                'text-bg-secondary'}

a.t-attf-style:
flex-shrink:0;
padding:5px 10px;
border-radius:20px;
font-size:0.72rem;
font-weight:500;
text-decoration:none;
white-space:nowrap;
#{
    'background:#0F6E56;color:#fff;'
    if active_filter == sf[0]
    else 'background:#f0f0f0;color:#555;'
}

span.t-attf-style:
margin-left:4px;
background:#{
    'rgba(255,255,255,.3)'
    if active_filter == sf[0]
    else 'rgba(0,0,0,.1)'
};
border-radius:10px;padding:1px 6px;font-size:0.65rem;

flex-shrink:0;font-size:0.65rem;font-weight:500;
border-radius:20px;padding:3px 8px;
#{
    'background:#E1F5EE;color:#085041;'
    if m['state'] == 'done' else
    'background:#E3F2FD;color:#1565C0;'
    if m['state'] == 'in_progress' else
    'background:#FFF9C4;color:#795548;'
    if m['state'] == 'confirmed' else
    'background:#FFEBEE;color:#C62828;'
}

a.style:
position:fixed;bottom:74px;right:16px;
                          background:#0F6E56;color:#fff;border-radius:50px;
                          padding:10px 16px;font-size:0.82rem;font-weight:600;
                          box-shadow:0 4px 16px rgba(15,110,86,.4);
                          text-decoration:none;z-index:99;
                          display:flex;align-items:center;gap:6px;

span.t-attf-class:
badge rounded-pill #{
                        'text-bg-success' if mission.state == 'done' else
                        'text-bg-primary' if mission.state == 'in_progress' else
                        'text-bg-warning' if mission.state == 'confirmed' else
                        'text-bg-danger' if mission.state == 'cancelled' else
                        'text-bg-secondary'}

i.t-attf-class:
fa #{
                                        'fa-star text-warning' if i < mission.rating
                                        else 'fa-star-o text-muted'}

span.t-attf-class:
badge rounded-pill #{
                        'text-bg-success' if provider.state == 'active' else
                        'text-bg-warning' if provider.state in ('submitted','verified') else
                        'text-bg-secondary'}

i.t-attf-class:
fa #{
                                            'fa-star text-warning' if i < provider.rating_avg
                                            else 'fa-star-o text-muted'}
